{ // **************************************************************** 
    // this call emulates a realtime check collection
    // it uses two environment variables
    // if they are not set, or set to dates prior to today, they will initialize with a value 30 minutes prior to now.
    // all subsequent calls to the API will then store the curUTC response parameter and use it for subsequent calls
    // check the postman console for logging
    // the logic is within the Pre-request Script as well as the Tests
    // ****************************************************************
    "applicationName": "{{appName}}",
    "busDt": "{{auto_env_today}}",
    "locRef": "{{env_locRef}}",
    "changedSinceUTC": "{{auto_env_changedSinceUTC}}"
}
